import api from './api';

const getData = (response) => response.data.data || response.data;

// ==================== DASHBOARD ====================
export const getDashboardStats = async () => {
    const response = await api.get('/admin/dashboard');
    return getData(response);
};

// ==================== APPLICATIONS (UPDATE) ====================

// OLD: /admin/applications -> NEW: /admin/review/applications
export const getApplications = async (params) => {
    const response = await api.get('/admin/review/applications', { params });
    return getData(response);
};

// OLD: /admin/applications/:id -> NEW: /admin/review/applications/:id
export const getApplicationById = async (id) => {
    const response = await api.get(`/admin/review/applications/${id}`);
    return getData(response);
};

// OLD: /admin/applications/:id/status -> NEW: /admin/review/applications/:id/status
export const updateApplicationStatus = async (id, data) => {
    const response = await api.put(`/admin/review/applications/${id}/status`, data);
    return getData(response);
};

// ==================== NEW: APPLICATION REVIEW APIs ====================

// Get all active posts with application counts (for merit page)
export const getActivePostsWithCounts = async (params = {}) => {
    const response = await api.get('/admin/review/posts', { params });
    return getData(response);
};

// Get applications for a specific post (merit-ordered)
export const getApplicationsForPost = async (postId, params = {}) => {
    const response = await api.get(`/admin/review/posts/${postId}/applications`, { params });
    return getData(response);
};

// Get application status history
export const getApplicationHistory = async (applicationId) => {
    const response = await api.get(`/admin/review/applications/${applicationId}/history`);
    return getData(response);
};

export const getApplicationRequiredDocuments = async (applicationId) => {
    const response = await api.get(`/admin/review/applications/${applicationId}/required-documents`);
    return getData(response);
};

export const downloadApplicationPdf = async (applicationId, options = {}) => {
    const includeImages = options.include_images !== false;
    const response = await api.post(
        `/admin/review/applications/${applicationId}/pdf`,
        { include_images: includeImages },
        {
            responseType: 'blob',
            params: { include_images: includeImages }
        }
    );
    return response;
};

// Bulk update application status (hold/select/reject)
export const bulkUpdateStatus = async (applicationIds, action, remarks = null) => {
    const response = await api.post('/admin/review/applications/bulk-action', {
        application_ids: applicationIds,
        action,
        remarks
    });
    return getData(response);
};

// ==================== MERIT LIST (NEW ENDPOINTS) ====================

export const generateMeritList = async (postId, districtId = null) => {
    const response = await api.post(`/admin/review/posts/${postId}/generate-merit`, {
        district_id: districtId
    });
    return getData(response);
};

export const getMeritList = async (postId, districtId = null) => {
    const params = { district_id: districtId };
    const response = await api.get(`/admin/review/posts/${postId}/merit-list`, { params });
    return getData(response);
};

export const exportMeritList = async (postId, format, districtId = null) => {
    const params = { post_id: postId, format };
    if (districtId) params.district_id = districtId;
    const response = await api.get('/admin/merit/export', { params });
    return getData(response);
};

// ==================== SELECTION OPERATIONS ====================

export const selectApplication = async (applicationId) => {
    const response = await api.post(`/admin/review/applications/${applicationId}/select`);
    return getData(response);
};

// ==================== CRON OPERATIONS (MANUAL TRIGGER) ====================

export const closeExpiredPosts = async () => {
    const response = await api.post('/admin/review/cron/close-expired-posts');
    return getData(response);
};
